// Eingabe validieren
const body = $input.first().json;

const required = ['tenant_slug', 'name', 'source_type'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Pflichtfeld fehlt: ${field}`);
  }
}

if (!['file', 'url', 'manual'].includes(body.source_type)) {
  throw new Error('source_type muss file, url oder manual sein');
}

if (body.source_type === 'file' && !body.file_base64) {
  throw new Error('file_base64 fehlt bei source_type=file');
}

if (body.source_type === 'url' && !body.origin_url) {
  throw new Error('origin_url fehlt bei source_type=url');
}

return [{ json: body }];

const tenant = $input.first().json;
if (!tenant || !tenant.id) {
  throw new Error(`Tenant nicht gefunden oder nicht aktiv: ${$('Validate Input').first().json.tenant_slug}`);
}
const input = $('Validate Input').first().json;
return [{ json: { ...input, tenant } }];

// Text-Extraktion aus verschiedenen Formaten
// Für PDF: n8n Extract from File Node oder externe API nötig
// Für HTML: eingebaut
// Für TXT/MD: direkt

const item = $input.first().json;
const fileType = item.file_type || 'txt';
let extractedText = '';

if (fileType === 'txt' || fileType === 'md') {
  // Direkt aus Binary Data
  extractedText = Buffer.from(item.file_base64 || '', 'base64').toString('utf-8');
} else if (fileType === 'html') {
  const raw = Buffer.from(item.file_base64 || '', 'base64').toString('utf-8');
  // Einfaches HTML-Stripping
  extractedText = raw
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();
} else if (fileType === 'pdf') {
  // PDF-Extraktion benötigt externen Service oder n8n PDF-Node
  // TODO: HTTP Request zu pdf-parser oder nutze n8n 'Extract From File'
  extractedText = item.extracted_text_from_pdf || '';
  if (!extractedText) {
    throw new Error('PDF-Extraktion nicht implementiert — nutze n8n Extract from File Node vor diesem Node');
  }
} else {
  // Fallback: URL-Download Ergebnis
  extractedText = item.url_content || Buffer.from(item.file_base64 || '', 'base64').toString('utf-8');
}

if (!extractedText || extractedText.length < 10) {
  throw new Error('Kein Text extrahiert — Datei leer oder Format nicht unterstützt');
}

return [{ json: { ...item, extracted_text: extractedText, char_count: extractedText.length } }];

// Text in Chunks aufteilen
const CHUNK_SIZE = 1000;
const CHUNK_OVERLAP = 150;

function chunkText(text, size, overlap) {
  const chunks = [];
  let start = 0;
  let index = 0;
  text = text.replace(/\r\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
  while (start < text.length) {
    let end = start + size;
    if (end < text.length) {
      const lastPeriod = text.lastIndexOf('.', end);
      const lastNewline = text.lastIndexOf('\n', end);
      const boundary = Math.max(lastPeriod, lastNewline);
      if (boundary > start + size * 0.5) end = boundary + 1;
    }
    const content = text.substring(start, Math.min(end, text.length)).trim();
    if (content.length > 50) {
      chunks.push({ chunk_index: index, content, char_count: content.length });
      index++;
    }
    start = end - overlap;
    if (start <= 0 || start >= text.length) break;
  }
  return chunks;
}

const item = $input.first().json;
const chunks = chunkText(item.extracted_text, CHUNK_SIZE, CHUNK_OVERLAP);

return chunks.map(chunk => ({
  json: { ...item, ...chunk, total_chunks: chunks.length }
}));
